mapper.select:
SELECT m.*, p.name AS category FROM music_rank m INNER JOIN playlist_music pm ON m.id = pm.music_id INNER JOIN playlist p ON pm.playlist_id = p.id WHERE pm.playlist_id = #{playlistId}
AND (m.title LIKE CONCAT('%', #{keyword}, '%') OR m.artist LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY m.star_rating DESC, m.create_time DESC
